package com.example.oidc.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.client.userinfo.OAuth2UserService;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.OAuth2Error;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.time.Instant;
import java.util.Set;

@Configuration
public class OidcTokenValidationConfig {

    private static final Logger logger = LoggerFactory.getLogger(OidcTokenValidationConfig.class);

    private static final Set<String> ALLOWED_AUDIENCES = Set.of();

    private final OidcProviderProperties oidcProperties;

    public OidcTokenValidationConfig(OidcProviderProperties oidcProperties) {
        this.oidcProperties = oidcProperties;
    }

    @Bean
    public OAuth2UserService<OidcUserRequest, OidcUser> oidcUserService() {
        OidcUserService delegate = new OidcUserService();

        return userRequest -> {
            OidcUser oidcUser = delegate.loadUser(userRequest);

            validateIdTokenClaims(oidcUser);

            logger.info("OIDC user authenticated successfully: sub={}", oidcUser.getSubject());

            return oidcUser;
        };
    }

    private void validateIdTokenClaims(OidcUser oidcUser) {
        // Validate issuer matches expected provider
        String issuer = oidcUser.getIssuer() != null ? oidcUser.getIssuer().toString() : null;
        if (issuer == null || !issuer.equals(oidcProperties.getIssuerUri())) {
            logger.warn("ID token issuer mismatch. Expected: {}, Got: {}", oidcProperties.getIssuerUri(), issuer);
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token issuer does not match expected issuer", null)
            );
        }

        // Validate audience contains our client ID
        if (oidcUser.getAudience() == null || !oidcUser.getAudience().contains(oidcProperties.getClientId())) {
            logger.warn("ID token audience does not contain expected client ID");
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token audience mismatch", null)
            );
        }

        // Validate token is not expired
        Instant expiresAt = oidcUser.getExpiresAt();
        if (expiresAt == null || Instant.now().isAfter(expiresAt)) {
            logger.warn("ID token has expired");
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token has expired", null)
            );
        }

        // Validate issued at time is not in the future (with small clock skew tolerance)
        Instant issuedAt = oidcUser.getIssuedAt();
        if (issuedAt == null || issuedAt.isAfter(Instant.now().plusSeconds(60))) {
            logger.warn("ID token issued at time is in the future");
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token issued at time is invalid", null)
            );
        }

        // Validate subject is present
        if (oidcUser.getSubject() == null || oidcUser.getSubject().isBlank()) {
            logger.warn("ID token missing subject claim");
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token missing subject claim", null)
            );
        }

        // Validate authorized party (azp) if present
        String azp = oidcUser.getIdToken().getClaim("azp");
        if (azp != null && !azp.equals(oidcProperties.getClientId())) {
            logger.warn("ID token authorized party does not match client ID");
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token authorized party mismatch", null)
            );
        }
    }
}

