package com.example.oidc.model;

import java.io.Serializable;
import java.time.Instant;
import java.util.Collections;
import java.util.Map;
import java.util.Set;

public class UserSession implements Serializable {

    private static final long serialVersionUID = 1L;

    private final String subject;
    private final String email;
    private final boolean emailVerified;
    private final String name;
    private final String preferredUsername;
    private final Set<String> roles;
    private final Instant authenticatedAt;
    private final Instant tokenExpiresAt;
    private final Map<String, Object> additionalClaims;

    private UserSession(Builder builder) {
        this.subject = builder.subject;
        this.email = builder.email;
        this.emailVerified = builder.emailVerified;
        this.name = builder.name;
        this.preferredUsername = builder.preferredUsername;
        this.roles = builder.roles != null ? Collections.unmodifiableSet(builder.roles) : Collections.emptySet();
        this.authenticatedAt = builder.authenticatedAt;
        this.tokenExpiresAt = builder.tokenExpiresAt;
        this.additionalClaims = builder.additionalClaims != null
            ? Collections.unmodifiableMap(builder.additionalClaims)
            : Collections.emptyMap();
    }

    public String getSubject() { return subject; }
    public String getEmail() { return email; }
    public boolean isEmailVerified() { return emailVerified; }
    public String getName() { return name; }
    public String getPreferredUsername() { return preferredUsername; }
    public Set<String> getRoles() { return roles; }
    public Instant getAuthenticatedAt() { return authenticatedAt; }
    public Instant getTokenExpiresAt() { return tokenExpiresAt; }
    public Map<String, Object> getAdditionalClaims() { return additionalClaims; }

    public boolean isTokenExpired() {
        return tokenExpiresAt != null && Instant.now().isAfter(tokenExpiresAt);
    }

    @Override
    public String toString() {
        // Never log sensitive token data
        return "UserSession{subject='" + subject + "', email='" + maskEmail(email) + "'}";
    }

    private String maskEmail(String email) {
        if (email == null || !email.contains("@")) return "***";
        int atIndex = email.indexOf('@');
        if (atIndex <= 2) return "***" + email.substring(atIndex);
        return email.substring(0, 2) + "***" + email.substring(atIndex);
    }

    public static class Builder {
        private String subject;
        private String email;
        private boolean emailVerified;
        private String name;
        private String preferredUsername;
        private Set<String> roles;
        private Instant authenticatedAt;
        private Instant tokenExpiresAt;
        private Map<String, Object> additionalClaims;

        public Builder subject(String subject) { this.subject = subject; return this; }
        public Builder email(String email) { this.email = email; return this; }
        public Builder emailVerified(boolean emailVerified) { this.emailVerified = emailVerified; return this; }
        public Builder name(String name) { this.name = name; return this; }
        public Builder preferredUsername(String preferredUsername) { this.preferredUsername = preferredUsername; return this; }
        public Builder roles(Set<String> roles) { this.roles = roles; return this; }
        public Builder authenticatedAt(Instant authenticatedAt) { this.authenticatedAt = authenticatedAt; return this; }
        public Builder tokenExpiresAt(Instant tokenExpiresAt) { this.tokenExpiresAt = tokenExpiresAt; return this; }
        public Builder additionalClaims(Map<String, Object> additionalClaims) { this.additionalClaims = additionalClaims; return this; }

        public UserSession build() {
            if (subject == null || subject.isBlank()) {
                throw new IllegalArgumentException("Subject is required for UserSession");
            }
            if (authenticatedAt == null) {
                authenticatedAt = Instant.now();
            }
            return new UserSession(this);
        }
    }
}

