package com.example.oidc.service;

import com.example.oidc.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.Collections;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

@Service
public class UserSessionService {

    private static final Logger logger = LoggerFactory.getLogger(UserSessionService.class);

    // Allowlist of claim names we extract into additional claims
    private static final Set<String> ALLOWED_ADDITIONAL_CLAIMS = Set.of(
        "locale", "zoneinfo", "picture", "profile", "updated_at"
    );

    public UserSession createUserSession(OidcUser oidcUser) {
        if (oidcUser == null) {
            throw new IllegalArgumentException("OidcUser cannot be null");
        }

        OidcIdToken idToken = oidcUser.getIdToken();
        if (idToken == null) {
            throw new IllegalArgumentException("ID token cannot be null");
        }

        String subject = sanitizeClaimValue(oidcUser.getSubject());
        String email = sanitizeClaimValue(oidcUser.getEmail());
        Boolean emailVerified = oidcUser.getEmailVerified();
        String name = sanitizeClaimValue(oidcUser.getFullName());
        String preferredUsername = sanitizeClaimValue(oidcUser.getPreferredUsername());

        Set<String> roles = extractRoles(oidcUser);
        Map<String, Object> additionalClaims = extractAllowedAdditionalClaims(idToken);

        UserSession session = new UserSession.Builder()
            .subject(subject)
            .email(email)
            .emailVerified(emailVerified != null && emailVerified)
            .name(name)
            .preferredUsername(preferredUsername)
            .roles(roles)
            .authenticatedAt(Instant.now())
            .tokenExpiresAt(idToken.getExpiresAt())
            .additionalClaims(additionalClaims)
            .build();

        logger.info("Created user session for subject: {}", subject);

        return session;
    }

    private Set<String> extractRoles(OidcUser oidcUser) {
        Set<String> roles = new HashSet<>();

        // Extract roles from realm_access claim (Keycloak-style)
        Object realmAccess = oidcUser.getIdToken().getClaim("realm_access");
        if (realmAccess instanceof Map) {
            @SuppressWarnings("unchecked")
            Map<String, Object> realmAccessMap = (Map<String, Object>) realmAccess;
            Object rolesObj = realmAccessMap.get("roles");
            if (rolesObj instanceof List) {
                @SuppressWarnings("unchecked")
                List<String> rolesList = (List<String>) rolesObj;
                for (String role : rolesList) {
                    String sanitized = sanitizeClaimValue(role);
                    if (sanitized != null && !sanitized.isBlank()) {
                        roles.add(sanitized);
                    }
                }
            }
        }

        // Extract from groups claim if present
        Object groups = oidcUser.getIdToken().getClaim("groups");
        if (groups instanceof List) {
            @SuppressWarnings("unchecked")
            List<String> groupsList = (List<String>) groups;
            for (String group : groupsList) {
                String sanitized = sanitizeClaimValue(group);
                if (sanitized != null && !sanitized.isBlank()) {
                    roles.add(sanitized);
                }
            }
        }

        return Collections.unmodifiableSet(roles);
    }

    private Map<String, Object> extractAllowedAdditionalClaims(OidcIdToken idToken) {
        Map<String, Object> additional = new HashMap<>();

        for (String claimName : ALLOWED_ADDITIONAL_CLAIMS) {
            Object claimValue = idToken.getClaim(claimName);
            if (claimValue != null) {
                if (claimValue instanceof String) {
                    additional.put(claimName, sanitizeClaimValue((String) claimValue));
                } else {
                    additional.put(claimName, claimValue);
                }
            }
        }

        return additional;
    }

    private String sanitizeClaimValue(String value) {
        if (value == null) {
            return null;
        }
        // Remove control characters and trim
        return value.replaceAll("[\\p{Cntrl}]", "").trim();
    }
}

