package com.example.oidc.controller;

import com.example.oidc.model.UserSession;
import com.example.oidc.service.UserSessionService;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import jakarta.servlet.http.HttpSession;

@Controller
public class DashboardController {

    private static final String USER_SESSION_ATTR = "userSession";

    private final UserSessionService userSessionService;

    public DashboardController(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
    }

    @GetMapping("/dashboard")
    public String dashboard(@AuthenticationPrincipal OidcUser oidcUser,
                            HttpSession httpSession,
                            Model model) {
        if (oidcUser == null) {
            return "redirect:/login";
        }

        UserSession userSession = (UserSession) httpSession.getAttribute(USER_SESSION_ATTR);

        if (userSession == null || userSession.isTokenExpired()) {
            userSession = userSessionService.createUserSession(oidcUser);
            httpSession.setAttribute(USER_SESSION_ATTR, userSession);
        }

        // Only expose safe display values to the view
        model.addAttribute("displayName", escapeHtml(userSession.getName()));
        model.addAttribute("email", escapeHtml(userSession.getEmail()));
        model.addAttribute("emailVerified", userSession.isEmailVerified());
        model.addAttribute("subject", escapeHtml(userSession.getSubject()));
        model.addAttribute("roles", userSession.getRoles());

        return "dashboard";
    }

    @GetMapping("/profile")
    public String profile(@AuthenticationPrincipal OidcUser oidcUser,
                          HttpSession httpSession,
                          Model model) {
        if (oidcUser == null) {
            return "redirect:/login";
        }

        UserSession userSession = (UserSession) httpSession.getAttribute(USER_SESSION_ATTR);
        if (userSession == null) {
            userSession = userSessionService.createUserSession(oidcUser);
            httpSession.setAttribute(USER_SESSION_ATTR, userSession);
        }

        model.addAttribute("userSession", userSession);
        return "profile";
    }

    private String escapeHtml(String input) {
        if (input == null) return null;
        return input
            .replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace("\"", "&quot;")
            .replace("'", "&#x27;");
    }
}

